python3 -c "
import json, re, sys

with open('schema.json') as f:
    schema = json.load(f)
with open('event.json') as f:
    data = json.load(f)

errors = []

# Top-level required fields
for field in schema.get('required', []):
    if field not in data:
        errors.append(f'Missing required top-level field: {field}')

# additionalProperties at top level
allowed = set(schema.get('properties', {}).keys())
for key in data:
    if key not in allowed:
        errors.append(f'Extra top-level property not allowed: {key}')

# event_type enum
et = data.get('event_type')
enum = schema['properties']['event_type'].get('enum', [])
if et not in enum:
    errors.append(f'event_type \"{et}\" not in enum {enum}')

# Check correct branch
payload = data.get('payload', {})

if et == 'user_signup':
    # payload must have exactly email and country
    required = ['email', 'country']
    for r in required:
        if r not in payload:
            errors.append(f'payload missing required field: {r}')
    # no extra fields
    allowed_payload = set(required)
    for k in payload:
        if k not in allowed_payload:
            errors.append(f'payload has extra field not allowed: {k}')
    # email pattern
    if 'email' in payload:
        if not re.match(r'^[^@]+@[^@]+\.[^@]+$', payload['email']):
            errors.append(f'email does not match pattern: {payload[\"email\"]}')
    # country pattern
    if 'country' in payload:
        if not re.match(r'^[A-Z]{2}$', payload['country']):
            errors.append(f'country does not match ISO alpha-2 pattern: {payload[\"country\"]}')
elif et == 'user_deletion':
    errors.append('Wrong branch selected: user_deletion instead of user_signup')

if errors:
    print('VALIDATION FAILED:')
    for e in errors:
        print(f'  - {e}')
    sys.exit(1)
else:
    print('ALL CHECKS PASSED')
    print(f'  event_type : {data[\"event_type\"]}')
    print(f'  payload    : {json.dumps(payload)}')
    print(f'  country    : {payload[\"country\"]} (ISO alpha-2 for Germany)')
"
